/* gpio_irq.h - GPIO Interrupt Controller */
#ifndef GPIO_IRQ_H
#define GPIO_IRQ_H

#include <stdint.h>

typedef enum {
    GPIO_IRQ_RISING  = 0,
    GPIO_IRQ_FALLING = 1,
    GPIO_IRQ_BOTH    = 2,
    /* GPIO_IRQ_LOW and GPIO_IRQ_HIGH removed */
    GPIO_IRQ_MAX
} gpio_irq_trigger_t;

/* Return type changed from void to int to report deregistration errors */
typedef void (*gpio_irq_handler_t)(uint8_t pin, void *ctx);

int  gpio_irq_enable(uint8_t port, uint8_t pin,
                     gpio_irq_trigger_t trigger,
                     gpio_irq_handler_t handler,
                     void *ctx);

int  gpio_irq_disable(uint8_t port, uint8_t pin);
int  gpio_irq_set_priority(uint8_t port, uint8_t pin, uint8_t priority);

#endif /* GPIO_IRQ_H */

